import os
import json
import csv
import sqlite3
from datetime import datetime

from flask import Flask, render_template, send_file, Response

app = Flask(__name__, template_folder="templates")

INPUT_DIR = "/app/workspace/data/input/"
OUTPUT_JSON = "/app/workspace/data/output.json"
DB_PATH = "/app/workspace/data/etl.db"
LOG_PATH = "/app/workspace/data/etl.log"


def _append_log(line: str) -> None:
    os.makedirs(os.path.dirname(LOG_PATH), exist_ok=True)
    ts = datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S")
    with open(LOG_PATH, "a", encoding="utf-8") as f:
        f.write(f"[{ts}] {line}\n")


def run_etl() -> None:
    try:
        os.makedirs(os.path.dirname(OUTPUT_JSON), exist_ok=True)

        records = []

        if os.path.isdir(INPUT_DIR):
            for name in sorted(os.listdir(INPUT_DIR)):
                if not name.endswith(".csv"):
                    continue
                path = os.path.join(INPUT_DIR, name)
                with open(path, newline="", encoding="utf-8") as f:
                    reader = csv.DictReader(f)
                    for row in reader:
                        # Preserve all columns; ensure every value is a string
                        clean = {}
                        for k, v in row.items():
                            if v is None:
                                clean[k] = ""
                            else:
                                clean[k] = str(v)
                        records.append(clean)

        # Write output.json as one flat JSON array
        with open(OUTPUT_JSON, "w", encoding="utf-8") as f:
            json.dump(records, f)

        # Insert into sqlite with exact schema
        conn = sqlite3.connect(DB_PATH)
        try:
            cur = conn.cursor()
            cur.execute("CREATE TABLE IF NOT EXISTS records (id INTEGER PRIMARY KEY, data TEXT)")
            cur.execute("DELETE FROM records")
            for rec in records:
                cur.execute("INSERT INTO records (data) VALUES (?)", (json.dumps(rec),))
            conn.commit()
        finally:
            conn.close()

        _append_log(f"SUCCESS: processed {len(records)} records")

    except Exception as e:
        _append_log(f"ERROR: {type(e).__name__}: {e}")
        raise


@app.get("/")
def index():
    return render_template("index.html")


@app.post("/trigger")
def trigger():
    run_etl()
    return Response("OK", status=200, mimetype="text/plain")


@app.get("/logs")
def logs():
    if not os.path.exists(LOG_PATH):
        return Response("", status=200, mimetype="text/plain")
    with open(LOG_PATH, "r", encoding="utf-8") as f:
        return Response(f.read(), status=200, mimetype="text/plain")


@app.get("/download")
def download():
    # Serve /app/workspace/data/output.json
    if not os.path.exists(OUTPUT_JSON):
        # Ensure file exists so browser download doesn't 404 if ETL hasn't run yet
        os.makedirs(os.path.dirname(OUTPUT_JSON), exist_ok=True)
        with open(OUTPUT_JSON, "w", encoding="utf-8") as f:
            f.write("[]")
    return send_file(OUTPUT_JSON, as_attachment=True)


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)
