  <pre id="logs" style="white-space: pre-wrap;"></pre>

  <script>
    async function fetchLogs() {
      const res = await fetch('/logs');
      const text = await res.text();
      document.getElementById('logs').textContent = text;
    }

    async function triggerETL() {
      const btn = document.getElementById('triggerBtn');
      btn.disabled = true;
      try {
        await fetch('/trigger', { method: 'POST' });
      } finally {
        btn.disabled = false;
        await fetchLogs();
      }
    }

    window.addEventListener('DOMContentLoaded', () => {
      document.getElementById('triggerBtn').addEventListener('click', triggerETL);
      fetchLogs();
    });
